#include <iostream>

using namespace std;

int main()
{
    int marks = 40;

    if (marks >= 90)
    {
        cout << "Grade A";
    }
    else if (marks >= 80)
    {
        cout << "Grade B";
    }
    else if (marks >= 70)
    {
        cout << "Grade C";
    }
    else
    {
        cout << "Grade F";
    }

    return 0;
}

